  2→
  3→/*
  4→ * gaeaW desktop — Tailwind-powered design system.
  5→ * Replaces the 121KB hand-written styles.css with utility classes
  6→ * and a thin custom theme layer (~500 lines).
  7→ *
  8→ * Multi-platform notes:
  9→ *  - System font stack only; no web-font fetches (offline-first, consistent).
 10→ *  - No backdrop-filter / blur (slow & inconsistent on Linux WebKitGTK).
 11→ *  - Colors via Tailwind theme tokens + prefers-color-scheme media query.
 12→ */
 13→
 14→@theme {
 15→  /*
 16→   * All tokens reference styles.css CSS variables (managed by :root[data-theme])
 17→   * so Tailwind utilities automatically follow the active theme (dark/light/warm/ice).
 18→   * styles.css is the single source of truth for color values.
 19→   */
 20→
 21→  /* ── surfaces ── */
 22→  --color-bg: var(--bg);
 23→  --color-bg-soft: var(--bg-soft);
 24→  --color-bg-elev: var(--bg-elev);
 25→  --color-bg-elev-2: var(--bg-elev-2);
 26→  --color-sidebar-bg: var(--sidebar-bg);
 27→  --color-sidebar-hover: var(--sidebar-hover);
 28→  --color-sidebar-active: var(--sidebar-active);
 29→  --color-border: var(--border);
 30→  --color-border-soft: var(--border-soft);
 31→
 32→  /* ── text ── */
 33→  --color-fg: var(--fg);
 34→  --color-fg-dim: var(--fg-dim);
 35→  --color-fg-faint: var(--fg-faint);
 36→
 37→  /* ── brand accent (warm clay) ── */
 38→  --color-accent: var(--accent);
 39→  --color-accent-fg: var(--accent-fg);
 40→  --color-accent-soft: var(--accent-soft);
 41→
 42→  /* ── semantic ── */
 43→  --color-ok: var(--ok);
 44→  --color-warn: var(--warn);
 45→  --color-err: var(--err);
 46→  --color-info: var(--info);
 47→  --color-warning: var(--warn);
 48→
 49→  /* ── diff ── */
 50→  --color-add-bg: var(--add-bg);
 51→  --color-add-fg: var(--add-fg);
 52→  --color-del-bg: var(--del-bg);
 53→  --color-del-fg: var(--del-fg);
 54→
 55→  /* ── syntax highlight ── */
 56→  --color-hl-keyword: var(--hl-keyword);
 57→  --color-hl-string: var(--hl-string);
 58→  --color-hl-number: var(--hl-number);
 59→  --color-hl-comment: var(--hl-comment);
 60→  --color-hl-func: var(--hl-func);
 61→  --color-hl-type: var(--hl-type);
 62→  --color-hl-builtin: var(--hl-builtin);
 63→  --color-hl-meta: var(--hl-meta);
 64→
 65→  /* ── scrollbar ── */
 66→  --color-scrollbar-track: transparent;
 67→  --color-scrollbar-thumb: var(--border);
 68→  --color-scrollbar-thumb-hover: #444956;
 69→
 70→  /* ── fonts ── */
 71→  --font-mono: var(--mono);
 72→  --font-sans: var(--sans);
 73→  --font-size-xs: 11px;
 74→  --font-size-sm: 12px;
 75→  --font-size-base: 13px;
 76→  --font-size-lg: 14px;
 77→
 78→  /* ── animation durations ── */
 79→  --transition-fast: 120ms;
 80→  --transition-normal: 150ms;
 81→  --transition-slow: 200ms;
 82→
 83→  --color-black: #000;
 84→  --color-white: #fff;
 85→}
 86→
 87→/* ── base layer ── */
 88→@layer base {
 89→  *, *::before, *::after {
 90→    box-sizing: border-box;
 91→  }
 92→
 93→  html, #root {
 94→    height: 100%;
 95→  }
 96→
 97→  /* Wails titlebar drag region */
 98→  [data-wails-draggable] {
 99→    -webkit-app-region: drag;
100→  }
101→  [data-wails-no-drag] {
102→    -webkit-app-region: no-drag;
103→  }
104→
105→  /* Remove default button styling */
106→  button {
107→    cursor: pointer;
108→    font-family: inherit;
109→  }
110→
111→  /* Focus ring */
112→  :focus-visible {
113→    outline: 2px solid var(--color-accent);
114→    outline-offset: 2px;
115→  }
116→
117→  /* Selection */
118→  ::selection {
119→    background: var(--color-accent-soft);
120→  }
121→}
122→
123→/* ── component utilities (keep for complex patterns not easily expressed in Tailwind) ── */
124→@utility scrollbar-thin {
125→  &::-webkit-scrollbar { width: 4px; height: 4px; }
126→}
127→@utility scrollbar-hidden {
128→  &::-webkit-scrollbar { display: none; }
129→}
130→@utility drag-region {
131→  --wails-draggable: drag;
132→  -webkit-app-region: drag;
133→}
134→@utility no-drag {
135→  --wails-draggable: no-drag;
136→  -webkit-app-region: no-drag;
137→}
138→
139→/* ── btn--primary — shared primary action button ─────────────────────────── */
140→@utility btn--primary {
141→  display: inline-flex;
142→  align-items: center;
143→  justify-content: center;
144→  gap: 5px;
145→  height: 28px;
146→  padding: 0 14px;
147→  border: none;
148→  border-radius: 7px;
149→  background: var(--color-accent);
150→  color: var(--color-accent-fg);
151→  font-size: 12px;
152→  font-weight: 600;
153→  cursor: pointer;
154→  transition: filter var(--transition-fast), transform var(--transition-fast);
155→}
156→.btn--primary:hover { filter: brightness(1.1); }
157→.btn--primary:active { transform: scale(0.97); }
158→.btn--primary:disabled {
159→  opacity: 0.4;
160→  cursor: default;
161→  filter: none;
162→  transform: none;
163→}
164→
165→/* ── close-btn — shared close (X) button ───────────────────────────────── */
166→@utility close-btn {
167→  display: inline-flex;
168→  align-items: center;
169→  justify-content: center;
170→  width: 26px;
171→  height: 26px;
172→  border: 1px solid var(--color-border);
173→  border-radius: 7px;
174→  background: var(--color-bg-soft);
175→  color: var(--color-fg-faint);
176→  cursor: pointer;
177→  transition: color var(--transition-fast), border-color var(--transition-fast), background var(--transition-fast);
178→}
179→.close-btn:hover {
180→  color: var(--color-fg);
181→  border-color: var(--color-fg-faint);
182→}
183→
184→/* ── toolbar-btn — shared toolbar action button ────────────────────────── */
185→@utility toolbar-btn {
186→  display: inline-flex;
187→  align-items: center;
188→  gap: 5px;
189→  height: 26px;
190→  padding-left: 11px;
191→  padding-right: 11px;
192→  border: 1px solid var(--color-border);
193→  border-radius: 7px;
194→  background: var(--color-bg-soft);
195→  color: var(--color-fg-dim);
196→  font-size: var(--font-size-xs);
197→  cursor: pointer;
198→  transition: color var(--transition-fast), border-color var(--transition-fast), background var(--transition-fast), transform var(--transition-fast);
199→}
200→.toolbar-btn:hover {
201→  color: var(--color-fg);
202→  border-color: var(--color-fg-faint);
203→}
204→.toolbar-btn:active { transform: scale(0.97); }
205→.toolbar-btn:disabled {
206→  opacity: 0.4;
207→  cursor: default;
208→}
209→.toolbar-btn:disabled:hover {
210→  color: var(--color-fg-dim);
211→  border-color: var(--color-border);
212→}
213→
214→/* Drawer resizing cursor lock */
215→.drawer--resizing,
216→.drawer--resizing * {
217→  cursor: col-resize !important;
218→  user-select: none;
219→}
220→.drawer--resizing .group > .pointer-events-none {
221→  background: var(--color-accent);
222→  box-shadow: 0 0 0 1px color-mix(in srgb, var(--color-accent) 24%, transparent);
223→}
224→
225→/* ── keyframes (referenced by Tailwind arbitrary animation utilities) ── */
226→@keyframes toast-in {
227→  from { opacity: 0; transform: translateY(-10px); }
228→  to   { opacity: 1; transform: translateY(0); }
229→}
230→
231→@keyframes drawer-in {
232→  from { transform: translateX(12px); opacity: 0.6; }
233→  to   { transform: translateX(0);    opacity: 1; }
234→}
235→@keyframes drawer-out {
236→  from { transform: translateX(0);  opacity: 1; }
237→  to   { transform: translateX(12px); opacity: 0; }
238→}
239→
240→@keyframes menu-in {
241→  from { opacity: 0; transform: translateY(-4px); }
242→  to   { opacity: 1; transform: translateY(0); }
243→}
244→
245→@keyframes fadeIn {
246→  from { opacity: 0; }
247→  to   { opacity: 1; }
248→}
249→
250→@keyframes scaleIn {
251→  from { opacity: 0; transform: scale(0.95); }
252→  to   { opacity: 1; transform: scale(1); }
253→}
254→
255→/* reasoning shimmer */
256→@keyframes shimmer-sweep {
257→  0%   { background-position: 200% 0; }
258→  100% { background-position: -200% 0; }
259→}
260→
261→/* ── accessibility: reduced motion ── */
262→@media (prefers-reduced-motion: reduce) {
263→  *, *::before, *::after {
264→    animation-duration: 0.01ms !important;
265→    animation-iteration-count: 1 !important;
266→    transition-duration: 0.01ms !important;
267→  }
268→}
