   1→/*
   2→ * gaeaW desktop — single-column, office-focused, terminal-flavored chat UI.
   3→ *
   4→ * Multi-platform notes:
   5→ *  - System font stack only; no web-font fetches (offline-first, consistent).
   6→ *  - Colors via CSS variables + prefers-color-scheme so the webview follows the OS.
   7→ *  - --wails-draggable marks the title region as an OS drag handle (macOS inset
   8→ *    title bar); interactive children opt out with --wails-draggable: no-drag.
   9→ *
  10→ * Design tokens: --ds-* prefix is canonical (per DESIGN.md); legacy short names
  11→ * (--bg, --fg, etc.) remain as aliases for backward compat with Tailwind classes.
  12→ */
  13→
  14→:root {
  15→  /* ── surfaces — deeper slate with clear 4-level hierarchy ──────────── */
  16→  --bg: #0F172A;
  17→  --bg-soft: #1B2336;
  18→  --bg-elev: #1E293B;
  19→  --bg-elev-2: #272F42;
  20→  --sidebar-bg: #0A111F;
  21→  --sidebar-hover: #18202F;
  22→  --sidebar-active: rgba(34, 197, 94, 0.14);
  23→  --border: #475569;
  24→  --border-soft: #334155;
  25→
  26→  /* ── text — high-contrast warm whites ──────────────────────────────── */
  27→  --fg: #F8FAFC;
  28→  --fg-dim: #CBD5E1;
  29→  --fg-faint: #94A3B8;
  30→
  31→  /* ── brand accent — run green (code success) ───────────────────────── */
  32→  --accent: #22C55E;
  33→  --accent-fg: #0F172A;
  34→  --accent-soft: rgba(34, 197, 94, 0.14);
  35→
  36→  /* ── semantic — crisp, accessible ──────────────────────────────────── */
  37→  --ok: #22C55E;
  38→  --warn: #F59E0B;
  39→  --err: #EF4444;
  40→  --info: #38BDF8;
  41→  --warning: #F59E0B;
  42→  --error: #EF4444;
  43→  --danger: #EF4444;
  44→
  45→  /* ── diff ──────────────────────────────────────────────────────────── */
  46→  --add-bg: rgba(34, 197, 94, 0.14);
  47→  --add-fg: #22C55E;
  48→  --del-bg: rgba(239, 68, 68, 0.14);
  49→  --del-fg: #EF4444;
  50→
  51→  /* ── syntax highlight (One Dark inspired, adjusted for new palette) ── */
  52→  --hl-keyword: #C084FC;  /* purple */
  53→  --hl-string: #22C55E;   /* run green */
  54→  --hl-number: #FB923C;   /* orange */
  55→  --hl-comment: #64748B;  /* slate */
  56→  --hl-func: #60A5FA;     /* blue */
  57→  --hl-type: #FBBF24;     /* amber */
  58→  --hl-builtin: #38BDF8;  /* sky */
  59→  --hl-meta: #94A3B8;     /* slate-400 */
  60→
  61→  /* ── layout ────────────────────────────────────────────────────────── */
  62→  --radius: 9px;
  63→  --maxw: 960px;
  64→  --mono: ui-monospace, "SF Mono", SFMono-Regular, Menlo, Consolas, "Liberation Mono", monospace;
  65→  --sans: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Noto Sans",
  66→    "Helvetica Neue", Arial, "PingFang SC", "Microsoft YaHei", sans-serif;
  67→
  68→  /* ── motion ────────────────────────────────────────────────────────── */
  69→  --dur-fast: 120ms;
  70→  --dur-base: 180ms;
  71→  --dur-slow: 340ms;
  72→  --dur-slower: 420ms;
  73→  --ease-out: cubic-bezier(0.2, 0.72, 0.2, 1);
  74→  --ease-decelerate: cubic-bezier(0.2, 0.7, 0.1, 1);
  75→  --ease-standard: cubic-bezier(0.25, 0.1, 0.25, 1);
  76→  --motion-pop-scale: 0.98;
  77→  --motion-rise: 4px;
  78→}
  79→/* -- Platform-specific font stacks -------------------------------------------------- */
  80→:root[data-platform="windows"] {
  81→  --font-ui: "Segoe UI Variable Text", "Segoe UI", "Microsoft YaHei UI",
  82→    "Microsoft YaHei", "Noto Sans SC", Arial, sans-serif;
  83→  --font-content-family: var(--font-ui);
  84→  --font-mono: "Cascadia Code", "Cascadia Mono", Consolas, "Liberation Mono",
  85→    ui-monospace, monospace;
  86→  --font-smoothing: auto;
  87→  --text-rendering: auto;
  88→}
  89→
  90→:root[data-platform="darwin"] {
  91→  --font-ui: -apple-system, BlinkMacSystemFont, "SF Pro Text", "PingFang SC",
  92→    "Hiragino Sans GB", "Helvetica Neue", Arial, sans-serif;
  93→  --font-content-family: var(--font-ui);
  94→  --font-mono: "SF Mono", SFMono-Regular, ui-monospace, Menlo, Monaco,
  95→    "Cascadia Code", Consolas, monospace;
  96→}
  97→
  98→:root[data-platform="linux"] {
  99→  --font-ui: system-ui, "Noto Sans", "Noto Sans CJK SC", "WenQuanYi Micro Hei",
