 315→/* box-sizing handled by tailwind.css base layer */
 316→html,
 317→html,
 318→body,
 319→#root {
 320→  height: 100%;
 321→  margin: 0;
 322→}
 323→body {
 324→  background: var(--bg);
 325→  color: var(--fg);
 326→  font-family: var(--sans);
 327→  font-size: 14px;
 328→  line-height: 1.6;
 329→  -webkit-font-smoothing: antialiased;
 330→  overflow: hidden;
 331→  transition: background-color var(--dur-slow) ease, color var(--dur-slow) ease;
 332→}
 333→
 334→.app {
 335→  height: 100%;
 336→  min-height: 0;
 337→}
 338→
 339→.layout {
 340→  --sidebar-width: var(--sidebar-expanded-width, 264px);
 341→  --workspace-width: 280px;
 342→  position: relative;
 343→  display: grid;
 344→  grid-template-columns: var(--sidebar-width) minmax(0, 1fr) minmax(0, var(--workspace-width));
 345→  height: 100%;
 346→  min-height: 0;
 347→  overflow: hidden;
 348→  background: var(--bg);
 349→  transition: grid-template-columns var(--dur-base) ease;
 350→}
 351→.layout--resizing {
 352→  cursor: col-resize;
 353→  transition: none;
 354→}
 355→.layout--resizing * {
 356→  user-select: none;
 357→}
 358→.layout--sidebar-collapsed {
 359→  --sidebar-width: 68px;
 360→}
 361→.layout--workspace-open {
 362→  grid-template-columns: var(--sidebar-width) minmax(200px, 1fr) minmax(0, var(--workspace-width));
 363→}
 364→.layout--workspace-maximized {
 365→  grid-template-columns: var(--sidebar-width) minmax(0, 1fr) minmax(0, var(--workspace-width));
 366→}
 367→.layout--workspace-maximized .chat-pane {
 368→  display: none;
 369→}
 370→
 371→.sidebar-resizer {
 372→  --wails-draggable: no-drag;
 373→  position: absolute;
 374→  top: 0;
 375→  bottom: 0;
 376→  left: calc(var(--sidebar-width) - 4px);
 377→  z-index: 12;
 378→  width: 8px;
 379→  padding: 0;
 380→  border: 0;
 381→  background: transparent;
 382→  cursor: col-resize;
 383→}
 384→.sidebar-resizer::after {
 385→  content: "";
 386→  position: absolute;
 387→  top: 0;
 388→  bottom: 0;
 389→  left: 50%;
 390→  width: 1px;
 391→  transform: translateX(-50%);
 392→  background: transparent;
 393→  transition: background var(--dur-fast), box-shadow var(--dur-fast);
 394→}
 395→.sidebar-resizer:hover::after,
 396→.sidebar-resizer:focus-visible::after,
 397→.layout--sidebar-resizing .sidebar-resizer::after {
 398→  background: var(--accent);
 399→  box-shadow: 0 0 0 1px color-mix(in srgb, var(--accent) 24%, transparent);
 400→}
 401→.layout--sidebar-collapsed .sidebar-resizer {
 402→  display: none;
 403→}
 404→.workspace-panel-resizer {
 405→  --wails-draggable: no-drag;
 406→  position: absolute;
 407→  top: 0;
 408→  right: calc(var(--workspace-width) - 4px);
 409→  bottom: 0;
 410→  z-index: 13;
 411→  width: 8px;
 412→  padding: 0;
 413→  border: 0;
 414→  background: transparent;
 415→  cursor: col-resize;
 416→  touch-action: none;
 417→}
 418→.workspace-panel-resizer::after {
 419→  content: "";
 420→  position: absolute;
 421→  top: 0;
 422→  bottom: 0;
 423→  left: 50%;
 424→  width: 1px;
 425→  transform: translateX(-50%);
 426→  background: transparent;
 427→  transition: background var(--dur-fast), box-shadow var(--dur-fast);
 428→}
 429→.workspace-panel-resizer:hover::after,
 430→.workspace-panel-resizer:focus-visible::after,
 431→.layout--workspace-resizing .workspace-panel-resizer::after {
 432→  background: var(--accent);
 433→  box-shadow: 0 0 0 1px color-mix(in srgb, var(--accent) 24%, transparent);
 434→}
 435→.chat-pane {
 436→  display: flex;
 437→  flex-direction: column;
 438→  min-width: 0;
 439→  min-height: 0;
 440→  background: var(--bg);
