 461→/* ── markdown prose ──────────────────────────────────────────────────────── */
 462→.md > :first-child {
 463→  margin-top: 0;
 464→}
 465→.md > :last-child {
 466→  margin-bottom: 0;
 467→}
 468→.md p {
 469→  margin: 0 0 8px;
 470→}
 471→.md h1,
 472→.md h2,
 473→.md h3,
 474→.md h4 {
 475→  margin: 14px 0 6px;
 476→  line-height: 1.3;
 477→  font-weight: 600;
 478→}
 479→.md h1 {
 480→  font-size: 1.4em;
 481→}
 482→.md h2 {
 483→  font-size: 1.22em;
 484→}
 485→.md h3 {
 486→  font-size: 1.08em;
 487→}
 488→.md h4 {
 489→  font-size: 1em;
 490→  color: var(--fg-dim);
 491→}
 492→.md ul,
 493→.md ol {
 494→  margin: 0 0 8px;
 495→  padding-left: 22px;
 496→}
 497→.md li {
 498→  margin: 3px 0;
 499→}
 500→.md li::marker {
 501→  color: var(--fg-faint);
 502→}
 503→.md a {
 504→  color: var(--accent);
 505→  text-decoration: none;
 506→}
 507→.md a:hover {
 508→  text-decoration: underline;
 509→}
 510→.md blockquote {
 511→  margin: 0 0 8px;
 512→  padding: 4px 14px;
 513→  border-left: 3px solid var(--accent);
 514→  background: color-mix(in srgb, var(--accent) 6%, transparent);
 515→  border-radius: 0 4px 4px 0;
 516→  color: var(--fg-dim);
 517→}
 518→.md hr {
 519→  border: none;
 520→  border-top: 1px solid var(--border);
 521→  margin: 18px 0;
 522→}
 523→.md-code {
 524→  font-family: var(--mono);
 525→  font-size: 0.88em;
 526→  background: var(--bg-elev-2);
 527→  border: 1px solid var(--border-soft);
 528→  border-radius: 5px;
 529→  padding: 1px 5px;
 530→}
 531→.md table {
 532→  border-collapse: collapse;
 533→  margin: 0 0 8px;
 534→  font-size: 13px;
 535→  display: block;
 536→  overflow-x: auto;
 537→  border-radius: 6px;
 538→  border: 1px solid var(--border);
 539→}
 540→.md th,
 541→.md td {
 542→  border: 1px solid var(--border);
 543→  padding: 5px 10px;
 544→  text-align: left;
 545→}
 546→.md th {
 547→  background: var(--bg-soft);
 548→  font-weight: 600;
 549→}
 550→.md tr:nth-child(even) td {
 551→  background: color-mix(in srgb, var(--bg-soft) 50%, var(--bg));
 552→}
 553→
 554→/* ── notices / phase ─────────────────────────────────────────────────────── */
 555→.notice {
 556→  margin: 3px 0;
 557→  font-size: 12.5px;
 558→  color: var(--fg-dim);
 559→  padding: 5px 11px;
 560→  border-left: 2px solid var(--border);
 561→  /* Listings (/skill, /hooks, /mcp, /memory, /model) are multi-line with leading
 562→     spaces; preserve them so the output isn't crammed onto one line. Monospace
 563→     keeps the indented entries aligned, like the CLI. */
 564→  white-space: pre-wrap;
 565→  font-family: var(--font-mono, ui-monospace, SFMono-Regular, Menlo, monospace);
 566→}
 567→.phase {
 568→  margin: 4px auto;
 569→  text-align: center;
 570→  font-size: 11px;
 571→  letter-spacing: 0.5px;
 572→  text-transform: uppercase;
 573→  color: var(--fg-faint);
 574→}
