 625→}
 626→.hljs-meta,
 627→.hljs-comment .hljs-doctag {
 628→  color: var(--hl-meta);
 629→}
 630→.hljs-emphasis {
 631→  font-style: italic;
 632→}
 633→.hljs-strong {
 634→  font-weight: 600;
 635→}
