 656→/* ── workspace side panel ────────────────────────────────────────────────── */
 657→.workspace-panel {
 658→  --workspace-tree-width: 280px;
 659→  --workspace-preview-min-width: 420px;
 660→  position: relative;
 661→  min-width: 0;
 662→  min-height: 0;
 663→  overflow: hidden;
 664→  display: grid;
 665→  grid-template-columns: minmax(0, 1fr) var(--workspace-tree-width);
 666→  height: 100%;
 667→  background: var(--bg);
 668→  border-left: 1px solid var(--border-soft);
 669→}
 670→.workspace-panel--tree-hidden {
