 672→}
 673→.workspace-panel--tree-hidden .workspace-files {
 674→  display: none;
 675→}
 676→.workspace-panel--preview-hidden {
 677→  grid-template-columns: minmax(0, 1fr);
 678→}
 679→.workspace-panel--preview-hidden .workspace-files {
 680→  background: var(--bg);
 681→}
 682→.workspace-preview,
 683→.workspace-files {
 684→  min-width: 0;
 685→  min-height: 0;
 686→}
 687→.workspace-preview {
 688→  display: flex;
 689→  flex-direction: column;
 690→  border-right: 1px solid var(--border-soft);
 691→}
 692→.workspace-tree-resizer {
 693→  --wails-draggable: no-drag;
 694→  position: absolute;
 695→  top: 0;
 696→  right: calc(var(--workspace-tree-width) - 4px);
 697→  bottom: 0;
 698→  z-index: 13;
 699→  width: 8px;
 700→  padding: 0;
 701→  border: 0;
 702→  background: transparent;
 703→  cursor: col-resize;
 704→  touch-action: none;
 705→}
 706→.workspace-tree-resizer::after {
 707→  content: "";
 708→  position: absolute;
 709→  top: 0;
 710→  bottom: 0;
 711→  left: 50%;
 712→  width: 1px;
 713→  transform: translateX(-50%);
 714→  background: transparent;
 715→  transition: background var(--dur-fast), box-shadow var(--dur-fast);
 716→}
 717→.workspace-tree-resizer:hover::after,
 718→.workspace-tree-resizer:focus-visible::after,
 719→.workspace-panel--tree-resizing .workspace-tree-resizer::after {
 720→  background: var(--accent);
 721→  box-shadow: 0 0 0 1px color-mix(in srgb, var(--accent) 24%, transparent);
 722→}
 723→.workspace-panel--tree-resizing,
 724→.workspace-panel--tree-resizing * {
 725→  cursor: col-resize !important;
 726→  user-select: none;
 727→}
 728→
 729→/* ── history drawer: click-to-resume rows with rename/delete actions ────────── */
 730→
 731→/* ── plan approval dock ─────────────────────────────────────────────────── */
 732→.plan-approval-dock {
 733→  position: fixed;
 734→  bottom: 176px;
 735→  left: 50%;
 736→  transform: translateX(-50%);
 737→  z-index: 40;
