 772→    width: auto;
 773→    max-width: none;
 774→  }
 775→}
 776→
 777→/* Respect the OS reduced-motion preference: squash all animations and force
 778→   instant scrolling so the UI feels immediate rather than web-like. */
 779→@media (prefers-reduced-motion: reduce) {
 780→  *,
 781→  *::before,
 782→  *::after {
 783→    animation-duration: 0.01ms !important;
 784→    animation-iteration-count: 1 !important;
 785→    transition-duration: 0.01ms !important;
 786→    scroll-behavior: auto !important;
 787→  }
 788→}
 789→
 790→/* ── message entrance ───────────────────────────────────────────────────── */
 791→@keyframes anim-fade-in {
 792→  to { opacity: 1; }
 793→}
 794→.msg--assistant {
 795→  animation: anim-fade-in 0.34s var(--ease-out) forwards;
 796→}
 797→
 798→/* ── startup splash ──────────────────────────────────────────────────────── */
 799→.startup-splash {
 800→  position: fixed;
 801→  inset: 0;
 802→  z-index: 9999;
 803→  display: flex;
 804→  align-items: center;
 805→  justify-content: center;
 806→  background: var(--bg);
 807→  transition: opacity 0.42s ease;
 808→}
 809→.startup-splash[data-leaving="true"] {
 810→  opacity: 0;
 811→  pointer-events: none;
 812→}
 813→.startup-splash__card {
 814→  display: flex;
 815→  flex-direction: column;
 816→  align-items: center;
 817→  animation: startup-splash-in 0.55s cubic-bezier(0.2, 0.7, 0.1, 1) both;
 818→}
 819→.startup-splash__mark {
 820→  width: 64px;
 821→  height: 64px;
 822→  display: flex;
 823→  align-items: center;
 824→  justify-content: center;
 825→  filter: drop-shadow(0 14px 22px color-mix(in srgb, var(--accent) 34%, transparent));
 826→  margin-bottom: 22px;
 827→}
 828→.startup-splash__mark img {
 829→  width: 64px;
 830→  height: 64px;
 831→  display: block;
 832→}
 833→.startup-splash__name {
 834→  font-size: 27px;
 835→  font-weight: 650;
 836→  letter-spacing: 0;
 837→  line-height: 1.1;
 838→  color: var(--fg);
 839→}
 840→.startup-splash__sub {
 841→  margin-top: 9px;
 842→  font-size: 13px;
 843→  letter-spacing: 0.05em;
 844→  color: var(--fg-faint);
 845→}
 846→.startup-splash__dots {
 847→  display: flex;
 848→  gap: 8px;
 849→  margin-top: 31px;
 850→}
 851→.startup-splash__dots span {
 852→  width: 6px;
 853→  height: 6px;
 854→  border-radius: 50%;
 855→  background: var(--fg-faint);
 856→  animation: startup-splash-pulse 1s ease-in-out infinite;
 857→}
 858→.startup-splash__dots span:nth-child(2) {
 859→  animation-delay: 0.16s;
 860→}
 861→.startup-splash__dots span:nth-child(3) {
 862→  animation-delay: 0.32s;
 863→}
 864→@keyframes startup-splash-in {
 865→  from {
 866→    opacity: 0;
 867→    transform: translateY(10px);
 868→  }
 869→  to {
 870→    opacity: 1;
 871→    transform: translateY(0);
 872→  }
 873→}
 874→@keyframes startup-splash-pulse {
 875→  0%, 100% {
 876→    opacity: 0.25;
 877→    transform: scale(0.8);
 878→  }
 879→  50% {
 880→    opacity: 1;
 881→    transform: scale(1);
 882→  }
 883→}
 884→
 885→/* ═══════════════════════════════════════════════════════════════════════════
 886→   BEM semantic message layer
 887→   ═════════════════════════════════════════════════════════════════════════ */
 888→
 889→.msg {
 890→  user-select: text;
 891→  -webkit-user-select: text;
 892→  margin: 6px auto;
 893→}
 894→
 895→/* ── user message bubble ───────────────────────────────────────────────── */
 896→.msg--user {
 897→  display: flex;
 898→  flex-direction: column;
 899→  align-items: flex-end;
 900→}
 901→.msg--user .msg__body {
 902→  max-width: 82%;
 903→  background: var(--bg-elev-2);
 904→  border: 1px solid var(--border-soft);
 905→  border-radius: 14px;
 906→  padding: 6px 12px;
 907→}
 908→.msg--user .msg__text {
 909→  white-space: pre-wrap;
 910→  word-break: break-word;
 911→  line-height: 1.65;
 912→  font-size: 14px;
 913→}
 914→
 915→/* ── assistant message card ────────────────────────────────────────────── */
 916→.msg--assistant {
 917→  color: var(--fg);
 918→  display: flex;
 919→  flex-direction: column;
 920→  gap: 4px;
 921→}
 922→.msg--assistant .msg__body {
 923→  line-height: 1.68;
 924→  user-select: text;
 925→  -webkit-user-select: text;
 926→}
 927→
 928→/* ── reasoning panel ───────────────────────────────────────────────────── */
 929→.reasoning {
 930→  margin-bottom: 2px;
 931→}
 932→.reasoning__head {
 933→  display: inline-flex;
 934→  align-items: center;
 935→  gap: 5px;
