167→interface WailsRuntime {
168→  EventsOn(name: string, cb: (...data: unknown[]) => void): () => void;
169→  BrowserOpenURL(url: string): void;
170→}
171→
172→declare global {
173→  interface Window {
174→    runtime?: WailsRuntime;
175→    go?: { main?: { App?: AppBindings } };
176→  }
177→}
178→
179→// Must match desktop/app.go's eventChannel constant.
180→const EVENT_CHANNEL = "agent:event";
181→
182→// Resolve the Wails binding at CALL time, not module-load time: in dev the Wails
183→// runtime can inject window.go AFTER this module first evaluates, so snapshotting
184→// once would pin the browser mock for the whole session (and show fake data — the
185→// dev mock's model list leaking into the real app was exactly this bug).
186→function realApp(): AppBindings | undefined {
187→  return typeof window !== "undefined" ? window.go?.main?.App : undefined;
188→}
189→
190→let mockSingleton: AppBindings | null = null;
191→function getMock(): AppBindings {
192→  if (!mockSingleton) mockSingleton = makeMockApp();
193→  return mockSingleton;
194→}
195→
196→// onEvent subscribes to the agent's typed event stream; returns an unsubscribe.
197→export function onEvent(cb: (e: WireEvent) => void): () => void {
198→  if (realApp() && typeof window !== "undefined" && window.runtime) {
199→    return window.runtime.EventsOn(EVENT_CHANNEL, (payload) => cb(payload as WireEvent));
200→  }
201→  return mockSubscribe(cb);
202→}
203→
204→// onUpdaterProgress subscribes to the auto-updater's progress events (a separate
205→// channel from the agent stream); returns an unsubscribe. Must match the event
206→// name emitted in desktop/updater_app.go.
207→export function onUpdaterProgress(cb: (p: UpdateProgress) => void): () => void {
208→  if (realApp() && typeof window !== "undefined" && window.runtime) {
209→    return window.runtime.EventsOn("updater:progress", (p) => cb(p as UpdateProgress));
210→  }
211→  updaterListeners.add(cb);
212→  return () => {
213→    updaterListeners.delete(cb);
214→  };
215→}
216→
217→// onReady subscribes to the agent:ready event fired when boot.Build completes.
218→// The frontend re-fetches Meta/Context/History when this lands.
219→export function onReady(cb: () => void): () => void {
220→  if (realApp() && typeof window !== "undefined" && window.runtime) {
221→    return window.runtime.EventsOn("agent:ready", () => cb());
222→  }
223→  // In dev mock, fire immediately since there's no real boot sequence.
224→  cb();
225→  return () => {};
226→}
227→
228→// app proxies each call to the live binding (or the dev mock only when truly
229→// outside the shell), so a late-injected window.go is picked up transparently.
230→export const app: AppBindings = new Proxy({} as AppBindings, {
231→  get(_t, prop) {
232→    const target = realApp() ?? getMock();
233→    const v = (target as unknown as Record<string, unknown>)[String(prop)];
234→    return typeof v === "function" ? (v as (...a: unknown[]) => unknown).bind(target) : v;
235→  },
236→});
237→
238→// openExternal opens a URL in the system browser (so links in rendered markdown
239→// don't navigate the webview away from the app). Falls back to window.open in the
240→// browser dev mock.
241→export function openExternal(url: string): void {
242→  if (typeof window !== "undefined" && window.runtime?.BrowserOpenURL) {
243→    window.runtime.BrowserOpenURL(url);
244→  } else if (typeof window !== "undefined") {
245→    window.open(url, "_blank", "noopener");
246→  }
247→}
248→
249→import {
250→  makeMockApp,
251→  mockSubscribe,
252→  updaterListeners,
253→} from "./mock";
254→
255→// ── compile-time drift check ──────────────────────────────────────────────
256→// _CheckGenToApp errors when a generated Go method has no TS counterpart in
257→// AppBindings. Fix: add the missing method to AppBindings, then `pnpm typecheck`.
258→// Methods intentionally excluded from the frontend can be listed in the Exclude
259→// union to silence the check.
260→import type * as GeneratedApp from "../../wailsjs/go/main/App";
261→
262→type AssertNever<T extends never> = T;
263→export type _CheckGenToApp = AssertNever<Exclude<keyof typeof GeneratedApp, keyof AppBindings | "QuitApp" | "ShowWindow" | "SetBypass" | "SetAgentMode" | "PermLevel">>;
