          <span className={`flex items-center gap-1.5 ${isPlanner ? "text-fg" : "text-fg-faint/60"}`}>
            <Brain size={12} className={isPlanner ? "text-purple-400" : ""} />
            <span className="font-medium">Hermes</span>
