import { useCallback, useEffect, useMemo, useState } from "react";
import { FileText, RefreshCw, Trash2, Clock, ExternalLink, FileSpreadsheet } from "lucide-react";
import type { DirEntry } from "../lib/types";
import { app } from "../lib/bridge";

interface ReportFile {
  name: string;
  path: string;
  modTime: number;
  isDir: boolean;
  ext: string;
}

const REPORT_EXTS = [".md", ".docx", ".xlsx", ".csv"];

function formatTime(ms: number): string {
  const d = new Date(ms);
  const now = new Date();
  const diff = now.getTime() - d.getTime();
  if (diff < 60000) return "刚刚";
  if (diff < 3600000) return `${Math.floor(diff / 60000)}分钟前`;
  if (diff < 86400000) return `${Math.floor(diff / 3600000)}小时前`;
  return d.toLocaleDateString([], { month: "short", day: "numeric" });
}

function getSourceTool(name: string): string {
  const n = name.toLowerCase();
  if (n.includes("survey") || n.includes("调查") || n.includes("初调") || n.includes("详调")) return "survey_report";
