export function ReportPreviewPanel({ cwd }: { cwd?: string }) {
  const [reports, setReports] = useState<ReportFile[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchReports = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const entries: DirEntry[] = await app.ListDir(".");
      const reportFiles: ReportFile[] = entries
        .filter((e) => {
          const ext = e.name.toLowerCase().slice(e.name.lastIndexOf("."));
          return REPORT_EXTS.includes(ext);
        })
        .map((e) => ({
